// UTIL FUNCTIONS
// =========================

const random = (min, max) =>
  Math.floor(Math.random() * (max - min + 1)) + min;

export const formatCurrency = (value) => {
  if (value >= 1000) {
    return `₹${(value / 1000).toFixed(1)}k`;
  }
  return `₹${value}`;
};

export const formatNumber = (value) => {
  if (value >= 1000) {
    return `${(value / 1000).toFixed(1)}k`;
  }
  return value.toString();
};



// =========================
// DASHBOARD STATS
// =========================

export const getDashboardStats = () => {
  return {
    totalUsers: {
      value: formatNumber(random(20, 30)), // 👈 20–30 users
      change: '+5%',
      changeType: 'positive',
    },

    applications: {
      value: formatNumber(random(10, 12)), // 👈 10–12
      change: '+3%',
      changeType: 'positive',
    },

    activeProjects: {
      value: formatNumber(random(5, 10)),
      change: '+2%',
      changeType: 'positive',
    },

    monthlyRevenue: {
      value: formatCurrency(random(25000, 35000)), // 👈 ₹25k–₹35k
      change: '+8%',
      changeType: 'positive',
    },

    escrowVolume: {
      value: formatCurrency(random(8000, 15000)),
      change: '+4%',
      changeType: 'positive',
    },

    openDisputes: {
      value: formatNumber(random(0, 2)),
      change: '0%',
      changeType: 'neutral',
    },
  };
};



