// REVENUE GRAPH
// =========================

export const getRevenueOverview = () => ({
  totalRevenue: 30000,

  data: [
    { month: 'Jan', revenue: 5000 },
    { month: 'Feb', revenue: 8000 },
    { month: 'Mar', revenue: 12000 },
    { month: 'Apr', revenue: 18000 },
    { month: 'May', revenue: 24000 },
    { month: 'Jun', revenue: 30000 },
  ],
});



